#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16

#pragma OPENCL EXTENSION cl_khr_fp64 : enable

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

__kernel void bpnn_layerforward_ocl(__global float *l1,
                                    __global float *l2,
                                    __global float *conn,
                                    __global float *partial_sum,
                                    __local float *local_conn,
                                    __local float *local_l1,
                                    int n1,
                                    int n2) {
    int j = get_global_id(1);
    int block_idx = get_global_id(0);

    if (j >= n2 || j == 0) return;

    int local_idx = get_local_id(0);
    int local_range = get_local_size(0);

    float sum = 0.0f;

    int start_k = block_idx * BLOCK_SIZE;
    int end_k = start_k + BLOCK_SIZE;
    if (end_k > n1 + 1) end_k = n1 + 1;

    for (int k = start_k; k < end_k; k++) {
        if (k <= n1) {
            float weight = conn[k * (n2 + 1) + j];
            float input_val = l1[k];
            sum += weight * input_val;
        }
    }

    partial_sum[block_idx * n2 + (j - 1)] = sum;
}

__kernel void bpnn_adjust_weights_ocl(__global float *delta,
                                      int ndelta,
                                      __global float *ly,
                                      int nly,
                                      __global float *w,
                                      __global float *oldw) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j > ndelta || j == 0) return;
    if (k > nly) return;

    float new_dw = (0.3f * delta[j] * ly[k]) + (0.3f * oldw[k * (ndelta + 1) + j]);

    w[k * (ndelta + 1) + j] += new_dw;
    oldw[k * (ndelta + 1) + j] = new_dw;
}
